import{p as r,bx as i,bh as d,I as l,U as e,A as n,W as t,X as o}from"./chunks/framework.BpabEsSf.js";const _=JSON.parse('{"title":"本地存储与加密技术文档","description":"","frontmatter":{"title":"本地存储与加密技术文档","date":"2026-05-16T13:15:00.000Z","permalink":"/reference/android-storage-security","categories":["技术内幕"],"tags":["Android","安全","加密"]},"headers":[],"relativePath":"02.配置/02.相关文档/02.Monica Android 本地存储与加密技术文档.md","filePath":"02.配置/02.相关文档/02.Monica Android 本地存储与加密技术文档.md","lastUpdated":1778928321000}'),p={name:"02.配置/02.相关文档/02.Monica Android 本地存储与加密技术文档.md"};function c(u,a,b,g,m,h){const s=i("Badge");return d(),l("div",null,[a[14]||(a[14]=e('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /02.配置\\02.相关文档\\02.Monica Android 本地存储与加密技术文档.md for this page in Markdown format</div><h1 id="🔒-monica-android-本地存储与加密技术文档" tabindex="-1">🔒 Monica Android 本地存储与加密技术文档 <a class="header-anchor" href="#🔒-monica-android-本地存储与加密技术文档" aria-label="Permalink to &quot;🔒 Monica Android 本地存储与加密技术文档&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">零知识保护原则 (Zero-Knowledge Architecture)</p><p><code>Monica Android</code> 采用多层全盘/字段级级联加密架构，确保用户的敏感资产（如密码、信用卡号、2FA 密钥、私密笔记等）在本地持久化与 WebDAV 备份过程中的绝对安全。系统核心遵循<strong>零知识保护</strong>原则：即使设备丢失或数据库文件被提取，攻击者在没有用户主密码的情况下，也绝对无法逆向出任何明文数据。</p></div><hr><h2 id="_1-本地数据存储" tabindex="-1">1. 本地数据存储 <a class="header-anchor" href="#_1-本地数据存储" aria-label="Permalink to &quot;1. 本地数据存储&quot;">​</a></h2><p>Monica 拒绝采用明文 SQLite 或不可靠的 KV 存储，而是拥抱 Google 官方推荐的 <strong>Modern Android Development (MAD)</strong> 架构进行结构化数据管理：</p>',6)),n("ul",null,[a[5]||(a[5]=n("li",null,[n("strong",null,"核心持久层"),t("：基于 "),n("code",null,"Room Persistence Library"),t(" (高级 SQLite 抽象层) 实现高内聚的数据访问对象 (DAO)。")],-1)),a[6]||(a[6]=n("li",null,[n("strong",null,"物理物理文件"),t("：存储在沙盒内部的 "),n("code",null,"password_database.db"),t(" 及其 WAL 日志文件中。")],-1)),n("li",null,[a[0]||(a[0]=n("strong",null,"物理隔离边界",-1)),a[1]||(a[1]=t()),o(s,{text:"隔离",type:"info"}),a[2]||(a[2]=t("：数据严密封锁在 Android 应用私有安全目录 (",-1)),a[3]||(a[3]=n("code",null,"/data/data/takagi.ru.monica/databases/",-1)),a[4]||(a[4]=t(")。在未解锁的非 Root 设备上，外部任何恶意进程均无权也无法越界访问。",-1))])]),a[15]||(a[15]=e(`<hr><h2 id="_2-核心加密技术架构" tabindex="-1">2. 核心加密技术架构 <a class="header-anchor" href="#_2-核心加密技术架构" aria-label="Permalink to &quot;2. 核心加密技术架构&quot;">​</a></h2><h3 id="_2-1-算法选型-aes-256-gcm" tabindex="-1">2.1 算法选型：AES-256-GCM <a class="header-anchor" href="#_2-1-算法选型-aes-256-gcm" aria-label="Permalink to &quot;2.1 算法选型：AES-256-GCM&quot;">​</a></h3><p>Monica 的核心加密引擎采用 <strong><code>AES-256-GCM</code></strong> (Advanced Encryption Standard with Galois/Counter Mode) 工业级对称加密算法。</p><div class="tip custom-block"><p class="custom-block-title">为什么选择 GCM 模式？</p><p>传统的 CBC 等模式只能提供<strong>保密性</strong>，容易遭受比特翻转（Bit-flipping）等篡改攻击。而 <code>GCM</code> 是一种 <strong>AEAD (Authenticated Encryption with Associated Data)</strong> 模式：</p><ol><li><strong>认证加密</strong>：在加密数据的同时，生成一个 16 字节的认证标签（Authentication Tag）。</li><li><strong>完整性校验</strong>：解密时系统会自动比对标签，任何对密文或 IV 的微小篡改都会导致解密直接熔断失败，从而彻底防御篡改和中间人注入。</li></ol></div><h3 id="_2-2-敏感数据流水线-securitymanager" tabindex="-1">2.2 敏感数据流水线 (SecurityManager) <a class="header-anchor" href="#_2-2-敏感数据流水线-securitymanager" aria-label="Permalink to &quot;2.2 敏感数据流水线 (SecurityManager)&quot;">​</a></h3><p>对于 <code>Room</code> 数据库中 <code>PasswordEntry</code> 表的敏感字段（如密码、密保答案等），Monica 在存取时会实时触发以下生命周期：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>[明文数据] ➔ 加上 12B 随机 IV ➔ [AES-256-GCM 引擎] ➔ 拼装 (IV + CipherText) ➔ Base64 编码 ➔ 写入 DB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol><li><strong>落盘前加密</strong>：调用 <code>SecurityManager</code> 拦截明文字符串，动态生成一个 <strong>12 字节的高熵随机 IV</strong> (初始化向量)。</li><li><strong>混合存储结构</strong>：数据最终以 <code>Base64(IV + CipherText)</code> 的复合字符串形式安全存入 SQLite 单元格中。</li><li><strong>读取时解密</strong>：从 Room 取出字符串 ➔ 自动进行 Base64 解碼 ➔ 切割出前 12 字节 IV 与后置密文 ➔ 联动硬件密钥还原明文。</li></ol><hr><h2 id="_3-主密码派生与硬件级密钥托管" tabindex="-1">3. 主密码派生与硬件级密钥托管 <a class="header-anchor" href="#_3-主密码派生与硬件级密钥托管" aria-label="Permalink to &quot;3. 主密码派生与硬件级密钥托管&quot;">​</a></h2><h3 id="_3-1-主密码高强度派生-pbkdf2" tabindex="-1">3.1 主密码高强度派生 (PBKDF2) <a class="header-anchor" href="#_3-1-主密码高强度派生-pbkdf2" aria-label="Permalink to &quot;3.1 主密码高强度派生 (PBKDF2)&quot;">​</a></h3><p>为了防止彩虹表撞库与离线暴力破解，用户输入的 App 主密码<strong>绝不落地、绝不存储哈希值</strong>，而是作为动态密钥派生的最高源头：</p>`,13)),n("ul",null,[a[12]||(a[12]=n("li",null,[n("strong",null,"核心算法"),t("："),n("code",null,"PBKDF2WithHmacSHA256"),t(" (Password-Based Key Derivation Function 2)。")],-1)),n("li",null,[a[7]||(a[7]=n("strong",null,"迭代参数",-1)),a[8]||(a[8]=t()),o(s,{text:"高防爆",type:"danger"}),a[9]||(a[9]=t("：配置高额的 ",-1)),a[10]||(a[10]=n("strong",null,[n("code",null,"100,000"),t(" 次密码学哈希迭代")],-1)),a[11]||(a[11]=t("，使攻击者的离线暴破算力成本呈指数级上升。",-1))]),a[13]||(a[13]=n("li",null,[n("strong",null,"动态盐值 (Salt)"),t("：每个设备在初始化时随机生成 16 字节的安全盐值，确保即使两个用户主密码相同，派生出的底层根密钥也完全独立。")],-1))]),a[16]||(a[16]=e(`<h3 id="_3-2-硬件安全区防线-android-keystore" tabindex="-1">3.2 硬件安全区防线 (Android KeyStore) <a class="header-anchor" href="#_3-2-硬件安全区防线-android-keystore" aria-label="Permalink to &quot;3.2 硬件安全区防线 (Android KeyStore)&quot;">​</a></h3><p>派生出的工作密钥与敏感配置，均由 Android Jetpack 安全组件（<code>EncryptedSharedPreferences</code> 与 <code>MasterKey</code>）强力守护：</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>硬件隔离 TEE / SE</strong> 核心 Master Key 的生成与加解密运算均在 Android <strong>硬件安全芯片</strong>（TEE 可信执行环境 或 SE 安全元件）中内网闭环运行。这意味着即使 Android 系统被攻破或被恶意 Root，密钥也<strong>无法从物理硬件中被剥离提取</strong>。</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>生物特征授权（BiometricPrompt）</strong> 支持联动指纹或 3D 结构光面部识别。生物核验成功后，由硬件安全区限时授权释放工作密钥，无需频繁暴露长串主密码，兼顾极致便利。</p></div><hr><h2 id="_4-远端备份加密规范-webdav" tabindex="-1">4. 远端备份加密规范 (WebDAV) <a class="header-anchor" href="#_4-远端备份加密规范-webdav" aria-label="Permalink to &quot;4. 远端备份加密规范 (WebDAV)&quot;">​</a></h2><p>当触发自动或手动的云端 WebDAV 异步备份任务时，Monica 的 <code>AutoBackupWorker</code> 会拉起独立的远端安全沙盒：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-FqIoj" id="tab-69Ax3eB" checked><label data-title="加密打包流水线" for="tab-69Ax3eB">加密打包流水线</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[沙盒核心 JSON 簇] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[打包为标准二进制 ZIP 流] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[提取用户设置的备份密码] ➔ [PBKDF2 100k 迭代派生密钥]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[AES-256-GCM 强力注入加密] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[附加魔法字节头 MONICA_ENC_V1] ➔ 生成独立的 .enc.zip ➔ WebDAV 上传</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></div></div><ul><li><strong>抗重放与去关联</strong>：每次生成的备份包都会重新生成高熵 Salt 和全新 IV。即使多次备份的数据完全一致，在云端生成的 <code>.enc.zip</code> 文件二进制结构也天差地别，防范云端服务商通过文件大小与特征进行隐私逆向。</li></ul><hr><h2 id="_5-安全矩阵总结" tabindex="-1">5. 安全矩阵总结 <a class="header-anchor" href="#_5-安全矩阵总结" aria-label="Permalink to &quot;5. 安全矩阵总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>安全维度</th><th>采用技术选型</th><th>防御的攻击类型</th></tr></thead><tbody><tr><td><strong>本地数据持久化</strong></td><td><code>AES-256-GCM (256-bit)</code></td><td>拖库攻击、物理翻转篡改攻击、中间人旁路注入</td></tr><tr><td><strong>主密码防暴破</strong></td><td><code>PBKDF2 + HMAC-SHA256</code> (100,000次迭代)</td><td>离线暴力破解、彩虹表碰撞、字典攻击</td></tr><tr><td><strong>运行时密钥保护</strong></td><td><code>Android KeyStore (TEE/SE 保护)</code></td><td>内存截取攻击、Root 权限文件越界窃取、物理拆机提取</td></tr><tr><td><strong>云端数据流转</strong></td><td><code>MONICA_ENC_V1</code> 二进制二进制流强加密</td><td>坚果云/Nextcloud 等云端基础设施被黑、备份链路监听</td></tr></tbody></table>`,12))])}const v=r(p,[["render",c]]);export{_ as __pageData,v as default};
